#!/usr/bin/env node
/**
 * Injects a release signing configuration into the Gradle project that
 * `expo prebuild` generates, and points the release build type at it.
 *
 * The `android/` directory is not committed (it is regenerated by prebuild),
 * so this patch runs in CI after prebuild. Signing values are read from
 * environment variables at build time; only the keystore file path is baked in.
 */
const fs = require('fs');

const buildGradlePath = 'android/app/build.gradle';
let gradle = fs.readFileSync(buildGradlePath, 'utf8');

const releaseSigningConfig = [
  '',
  '        release {',
  '            storeFile file("release.keystore")',
  '            storePassword System.getenv("ANDROID_KEYSTORE_PASSWORD")',
  '            keyAlias System.getenv("ANDROID_KEY_ALIAS")',
  '            keyPassword System.getenv("ANDROID_KEY_PASSWORD")',
  '        }',
  '',
].join('\n');

// Add the release signingConfig after the existing debug block (idempotent).
if (!/release\s*\{[^}]*storeFile/.test(gradle)) {
  const before = gradle;
  gradle = gradle.replace(
    /(signingConfigs\s*\{\s*debug\s*\{[\s\S]*?\}\s*)/,
    `$1${releaseSigningConfig}`,
  );
  if (gradle === before) {
    throw new Error('Could not locate the signingConfigs { debug { ... } } block to patch.');
  }
}

// Point the release build type at the release signing config (not debug).
if (/buildTypes\s*\{[\s\S]*?release\s*\{[\s\S]*?signingConfig\s+signingConfigs\.release/.test(gradle)) {
  console.log('Release build type already uses signingConfigs.release; nothing to repoint.');
} else {
  const beforeBuildType = gradle;
  gradle = gradle.replace(
    /(buildTypes\s*\{[\s\S]*?release\s*\{[\s\S]*?)signingConfig\s+signingConfigs\.debug/,
    '$1signingConfig signingConfigs.release',
  );
  if (gradle === beforeBuildType) {
    throw new Error('Could not locate the release build type signingConfig to repoint.');
  }
}

fs.writeFileSync(buildGradlePath, gradle);
console.log('Patched android/app/build.gradle with release signing config.');
